cat .leandag/dag.json | python3 -c "
import json, sys
dag = json.load(sys.stdin)
nodes = dag['nodes']
# Chapter breakdown
chapters = {}
for n in nodes:
    ch = n.get('chapter', 'unknown')
    if ch not in chapters:
        chapters[ch] = {'proved': 0, 'has_sorry': 0, 'mathlib_ok': 0, 'not_proved_clean': 0, 'total': 0}
    chapters[ch]['total'] += 1
    if n.get('proved'): chapters[ch]['proved'] += 1
    if n.get('has_sorry'): chapters[ch]['has_sorry'] += 1
    if n.get('mathlib_ok'): chapters[ch]['mathlib_ok'] += 1
    if not n.get('proved') and not n.get('mathlib_ok') and not n.get('has_sorry'):
        chapters[ch]['not_proved_clean'] += 1
for ch, s in sorted(chapters.items()):
    print(f'{ch}:')
    print(f'  total={s[\"total\"]} proved={s[\"proved\"]} has_sorry={s[\"has_sorry\"]} mathlib_ok={s[\"mathlib_ok\"]} not_proved_clean={s[\"not_proved_clean\"]}')
